import logging
import json
import azure.functions as func


def main(req: func.HttpRequest) -> func.HttpResponse:
    """
    Azure Function HTTP API endpoint for a single-page application.
    Handles CORS preflight (OPTIONS) and standard API requests.
    """
    logging.info('Python HTTP trigger function processed a request.')

    # Define CORS headers - allow all origins for development flexibility
    cors_headers = {
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, PATCH, OPTIONS",
        "Access-Control-Allow-Headers": "Content-Type, Authorization, X-Requested-With, Accept, Origin",
        "Access-Control-Max-Age": "86400",
        "Access-Control-Expose-Headers": "Content-Length, X-Request-Id"
    }

    # Handle CORS preflight OPTIONS request
    if req.method == "OPTIONS":
        return func.HttpResponse(
            status_code=204,
            headers=cors_headers
        )

    # Route handling based on method and path
    route = req.route_params.get("route", "")

    try:
        if req.method == "GET":
            response_data = handle_get(req, route)
        elif req.method == "POST":
            response_data = handle_post(req, route)
        elif req.method == "PUT":
            response_data = handle_put(req, route)
        elif req.method == "DELETE":
            response_data = handle_delete(req, route)
        elif req.method == "PATCH":
            response_data = handle_patch(req, route)
        else:
            response_data = {
                "error": f"Method {req.method} not supported",
                "status": 405
            }
            return func.HttpResponse(
                body=json.dumps(response_data),
                status_code=405,
                headers={**cors_headers, "Content-Type": "application/json"}
            )

        status_code = response_data.pop("status", 200)

        return func.HttpResponse(
            body=json.dumps(response_data),
            status_code=status_code,
            headers={**cors_headers, "Content-Type": "application/json"}
        )

    except ValueError as ve:
        logging.error(f"Validation error: {str(ve)}")
        error_response = {
            "error": "Bad Request",
            "message": str(ve)
        }
        return func.HttpResponse(
            body=json.dumps(error_response),
            status_code=400,
            headers={**cors_headers, "Content-Type": "application/json"}
        )
    except Exception as e:
        logging.error(f"Internal server error: {str(e)}")
        error_response = {
            "error": "Internal Server Error",
            "message": "An unexpected error occurred"
        }
        return func.HttpResponse(
            body=json.dumps(error_response),
            status_code=500,
            headers={**cors_headers, "Content-Type": "application/json"}
        )


def handle_get(req: func.HttpRequest, route: str) -> dict:
    """Handle GET requests."""
    logging.info(f"GET request for route: {route}")

    # Parse query parameters
    params = dict(req.params)

    if route == "health":
        return {
            "status": 200,
            "message": "API is healthy",
            "version": "1.0.0"
        }

    if route == "items":
        # Example: return a list of items
        # In production, this would query a database
        page = int(params.get("page", 1))
        page_size = int(params.get("page_size", 10))

        sample_items = [
            {"id": i, "name": f"Item {i}", "description": f"Description for item {i}"}
            for i in range((page - 1) * page_size + 1, page * page_size + 1)
        ]

        return {
            "status": 200,
            "data": sample_items,
            "pagination": {
                "page": page,
                "page_size": page_size,
                "total": 100  # Example total
            }
        }

    if route.startswith("items/"):
        item_id = route.split("/")[-1]
        return {
            "status": 200,
            "data": {
                "id": item_id,
                "name": f"Item {item_id}",
                "description": f"Detailed description for item {item_id}"
            }
        }

    # Default response for unknown routes
    return {
        "status": 200,
        "message": "SPA API is running",
        "available_routes": [
            "GET /api/health",
            "GET /api/items",
            "GET /api/items/{id}",
            "POST /api/items",
            "PUT /api/items/{id}",
            "PATCH /api/items/{id}",
            "DELETE /api/items/{id}"
        ]
    }


def handle_post(req: func.HttpRequest, route: str) -> dict:
    """Handle POST requests."""
    logging.info(f"POST request for route: {route}")

    try:
        request_body = req.get_json()
    except ValueError:
        raise ValueError("Request body must be valid JSON")

    if route == "items":
        # Validate required fields
        if not request_body.get("name"):
            raise ValueError("Field 'name' is required")

        # In production, save to database
        new_item = {
            "id": "new-generated-id",
            "name": request_body.get("name"),
            "description": request_body.get("description", ""),
            "created": True
        }

        return {
            "status": 201,
            "message": "Item created successfully",
            "data": new_item
        }

    return {
        "status": 404,
        "error": f"POST route '{route}' not found"
    }


def handle_put(req: func.HttpRequest, route: str) -> dict:
    """Handle PUT requests."""
    logging.info(f"PUT request for route: {route}")

    try:
        request_body = req.get_json()
    except ValueError:
        raise ValueError("Request body must be valid JSON")

    if route.startswith("items/"):
        item_id = route.split("/")[-1]

        if not request_body.get("name"):
            raise ValueError("Field 'name' is required for full update")

        updated_item = {
            "id": item_id,
            "name": request_body.get("name"),
            "description": request_body.get("description", ""),
            "updated": True
        }

        return {
            "status": 200,
            "message": f"Item {item_id} updated successfully",
            "data": updated_item
        }

    return {
        "status": 404,
        "error": f"PUT route '{route}' not found"
    }


def handle_patch(req: func.HttpRequest, route: str) -> dict:
    """Handle PATCH requests for partial updates."""
    logging.info(f"PATCH request for route: {route}")

    try:
        request_body = req.get_json()
    except ValueError:
        raise ValueError("Request body must be valid JSON")

    if route.startswith("items/"):
        item_id = route.split("/")[-1]

        # In production, merge with existing data from database
        patched_fields = {k: v for k, v in request_body.items()}

        return {
            "status": 200,
            "message": f"Item {item_id} partially updated",
            "data": {
                "id": item_id,
                "patched_fields": patched_fields
            }
        }

    return {
        "status": 404,
        "error": f"PATCH route '{route}' not found"
    }


def handle_delete(req: func.HttpRequest, route: str) -> dict:
    """Handle DELETE requests."""
    logging.info(f"DELETE request for route: {route}")

    if route.startswith("items/"):
        item_id = route.split("/")[-1]

        # In production, delete from database
        return {
            "status": 200,
            "message": f"Item {item_id} deleted successfully",
            "data": {"id": item_id, "deleted": True}
        }

    return {
        "status": 404,
        "error": f"DELETE route '{route}' not found"
    }